const C={bg:"#FAFAF7",card:"#FFFFFF",warm:"#F4F1EB",cream:"#FBF9F5",text:"#1C1C30",mid:"#3E3E56",lt:"#6E6E82",faint:"#A0A0B0",pri:"#7851A9",priDk:"#5C3D8F",priLt:"#9B7EC8",priBg:"#F3EEFA",teal:"#0E9577",navy:"#1E3A5F",coral:"#E05535",emerald:"#2A8C5A",amber:"#D4930D",plum:"#8B3A8B",slate:"#3F6B7A",rose:"#C93B6B",olive:"#5A7F2A",indigo:"#4338CA",border:"#E5E2D9",borderLt:"#EEEAE2",sh:"0 1px 3px rgba(28,28,48,.04),0 5px 15px rgba(28,28,48,.03)",shH:"0 2px 8px rgba(28,28,48,.07),0 12px 32px rgba(28,28,48,.05)"};
